    normalized = normalized.replace(/(^|[^\p{L}\p{N}_])[-вИТ]\s*(\d+)/gu, "$1\u043C\u0438\u043D\u0443\u0441 $2");
    normalized = normalized.replace(/(?<=[\p{L}])\s+-\s+(?=[\p{L}\p{N}])/gu, ". ");
    normalized = normalized.replace(/^[\s\-вАУвАФ_=*вАҐ¬ЈвЛЕвИЩ]+$/gu, " ");
    normalized = normalized.replace(/[вАФвАУ]/g, ". ");
