    async function revealLearningSolution() {
      const state = stateApi.get();
      const gate = state.learningGate;
      if (!gate?.active) return;
      if (gate.loading) {
        toast("\u0420\u0435\u0448\u0435\u043D\u0438\u0435 \u0443\u0436\u0435 \u0433\u043E\u0442\u043E\u0432\u0438\u0442\u0441\u044F");
        return;
      }
      let result = String(gate.result || "").trim();
      if (!result) {
        const requestId = Date.now() + "-" + Math.random().toString(16).slice(2);
        stateApi.updateLearningGate({ loading: true, requestId });
        view();
        try {
          const response = await explainTaskDetailed(gate.task || state.draft);
          applyAccessStatus(response.access);
          result = normalizeAssistantText(response.result);
          if (stateApi.get().learningGate?.requestId !== requestId) return;
          if (!result) throw new Error("\u0421\u0435\u0440\u0432\u0435\u0440 \u043D\u0435 \u0432\u0435\u0440\u043D\u0443\u043B \u0433\u043E\u0442\u043E\u0432\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435.");
          stateApi.updateLearningGate({
            loading: false,
            result,
            coach: buildLearningCoach({ taskText: gate.task || state.draft, resultText: result })
          });
        } catch (error) {
          if (stateApi.get().learningGate?.requestId !== requestId) return;
          stateApi.clearLearningGate();
          const errorMessage = String(error?.message || "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u043E\u0442\u0432\u0435\u0442 \u043E\u0442 \u0441\u0435\u0440\u0432\u0435\u0440\u0430.");
          if (looksLikeTechnicalMaintenancePayload(errorMessage)) {
            stateApi.setResult("");
            view();
            return;
          }
          if (error?.limitReached || errorMessage.includes("\u041B\u0438\u043C\u0438\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u043D\u0430 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u0443\u0436\u0435 \u0438\u0441\u0447\u0435\u0440\u043F\u0430\u043D")) {
            applyAccessStatus(error.access);
            stateApi.setResult(errorMessage);
            view();
            toast(errorMessage);
            return;
          }
          stateApi.setResult("\u041E\u0448\u0438\u0431\u043A\u0430: " + errorMessage);
          view();
          return;
        }
      }
      const latestGate = stateApi.get().learningGate || gate;
      stateApi.setResult(result);
      stateApi.setGuideStepIndex(0);
      if (!latestGate.savedToHistory && hasActiveSubscription()) {
        stateApi.pushHistory({
          id: Date.now(),
          task: latestGate.task || state.draft,
          result,
          createdAt: (/* @__PURE__ */ new Date()).toISOString()
        });
      }
      stateApi.updateLearningGate({ revealed: true, loading: false, result, savedToHistory: true });
      view();
    }
    function handleGuideAction(action) {
      const state = stateApi.get();
      if (!isGuidedSolutionActive(state)) return;
      const total = getGuidedStageCount({
        explanationText: state.currentResult || "",
        taskText: state.draft || ""
      });
      const current = state.guideStepIndex || 0;
      if (action === "next") {
        stateApi.setGuideStepIndex(Math.min(current + 1, Math.max(total - 1, 0)));
        view();
        return;
      }
      if (action === "back") {
        stateApi.setGuideStepIndex(Math.max(current - 1, 0));
        view();
        return;
      }
      if (action === "coach" || action === "reset") {
        stateApi.setGuideStepIndex(0);
        if (state.learningGate?.active) {
          stateApi.updateLearningGate({ revealed: false, loading: false });
          stateApi.setResult("");
        }
        view();
      }
    }
